const attachments = $json.attachments || []
const pdf = attachments.find(a =>
  (a.name || '').toLowerCase().endsWith('.pdf') ||
  a.contentType === 'application/pdf'
)

if (!pdf || !pdf.contentBytes) {
  return [{ json: { hasPdf: false } }]
}

const fileName = `email-${Date.now()}.pdf`

return [{
  json: {
    hasPdf: true,
    pdfBase64: pdf.contentBytes,
    fileName,
    emailSubject: $json.subject || '',
    emailFrom: $json.from?.emailAddress?.address || ''
  },
  binary: {
    data: {
      data: pdf.contentBytes,
      mimeType: 'application/pdf',
      fileName: pdf.name || fileName
    }
  }
}]

const pdfBase64 = $json.pdfBase64

const body = {
  contents: [{ parts: [
    { inline_data: { mime_type: 'application/pdf', data: pdfBase64 } },
    { text: 'Ist dieses Dokument eine Rechnung, ein Kassenbon oder eine Quittung (d.h. ein Beleg über eine erbrachte Leistung oder einen Kauf)? Antworte NUR mit JSON: {"is_invoice": true} oder {"is_invoice": false}. Lieferscheine, Angebote, Newsletter, Werbe-E-Mails, Bestellbestätigungen ohne Zahlungsaufforderung, Verträge und Mahnungen gelten NICHT als Rechnung.' }
  ]}],
  generationConfig: {
    response_mime_type: 'application/json',
    response_schema: {
      type: 'OBJECT',
      properties: { is_invoice: { type: 'BOOLEAN' } },
      required: ['is_invoice']
    }
  }
}

return [{ json: { checkBody: JSON.stringify(body), pdfBase64: $json.pdfBase64, fileName: $json.fileName } }]

const rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text
let isInvoice = false
try {
  const parsed = typeof rawText === 'string' ? JSON.parse(rawText) : (rawText ?? {})
  isInvoice = parsed.is_invoice === true
} catch {}

const prev = $('Rechnungsprüfung vorbereiten').first().json

return [{ json: { isInvoice, pdfBase64: prev.pdfBase64, fileName: prev.fileName } }]

// Alle Kategorien-Items zu einem Array zusammenfassen
const all = $input.all()
const kategorien = all.map(item => ({
  wert: item.json.wert,
  beschreibung: item.json.beschreibung
}))

const pdfData = $('Rechnungsprüfung vorbereiten').first().json

return [{
  json: {
    kategorien,
    pdfBase64: pdfData.pdfBase64,
    fileName:  pdfData.fileName
  }
}]

const CARD_MAP = {
  '1380': 'spesen_philipp_1380',
  '0744': 'spesen_philipp_0744',
  '6362': 'firmenkarte_6362',
  '0660': 'firmenkarte_0660'
}

function normalizeDate(raw) {
  if (!raw) return null
  const s = String(raw).trim()
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s
  if (s.includes('.')) {
    const parts = s.split('.')
    if (parts.length === 3) {
      const [d, m, y] = parts
      return `${y.trim()}-${m.trim().padStart(2,'0')}-${d.trim().padStart(2,'0')}`
    }
  }
  const p = new Date(s)
  return isNaN(p.getTime()) ? null : p.toISOString().split('T')[0]
}

const rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text
let ocr = typeof rawText === 'string' ? JSON.parse(rawText) : (rawText ?? {})

// Proforma → alle Steuerfelder null erzwingen
if (ocr.is_proforma) {
  ocr = { ...ocr, tax_rate: null, tax_amount_10: null, tax_amount_20: null, net_amount_10: null, net_amount_20: null }
}
// 19% → 20% für Österreich
if (ocr.tax_rate === 19) ocr = { ...ocr, tax_rate: 20 }
// Kein Steuersatz aber Betrag vorhanden → österreichischer Standard 20%
if (!ocr.is_proforma && !ocr.tax_rate && ocr.net_amount) ocr = { ...ocr, tax_rate: 20 }

// effectiveNetto: Aufschlüsselung bevorzugen
const n10  = ocr.net_amount_10 ?? 0
const n20  = ocr.net_amount_20 ?? 0
const n0   = ocr.net_amount_0  ?? 0
const sum  = n10 + n20 + n0
const netto = sum > 0 ? Math.round(sum * 100) / 100 : (ocr.net_amount ?? 0)

const digits = ocr.card_last_four ? String(ocr.card_last_four).trim() : null
const karte  = digits ? (CARD_MAP[digits] ?? 'sonstige') : null

const pdfUrl = $('Gemini Request vorbereiten').first().json.pdfUrl

return [{
  json: {
    rechnungsnr:    ocr.invoice_number?.trim() || `EMAIL-${Date.now()}`,
    rechnungsdatum: normalizeDate(ocr.invoice_date) || null,
    faelligkeit:    normalizeDate(ocr.due_date)     || null,
    betrag:         netto,
    ust_satz:       ocr.is_proforma ? 0 : (ocr.tax_rate ?? 20),
    rechnungstyp:   ocr.invoice_type || null,
    betrag_10:      ocr.net_amount_10 ?? null,
    betrag_20:      ocr.net_amount_20 ?? null,
    betrag_0:       ocr.net_amount_0  ?? null,
    mwst_10:        ocr.tax_amount_10 ?? null,
    mwst_20:        ocr.tax_amount_20 ?? null,
    karte:          karte || null,
    pdf_url:        pdfUrl,
    status:         'eingegangen',
    ocr_json:       ocr
  }
}]
